export function toEnglish(value: string) {
  const trimmed = value.trim();
  const direct = englishCopy[trimmed];
  if (direct) return value.replace(trimmed, direct);
  return value
    .replace(/(\d+) créateurs? sélectionnés?/g, '$1 selected creators')
    .replace(/(\d+) profils?/g, '$1 profiles')
    .replace(/(\d+) résultats?/g, '$1 results')
    .replace(/(\d[\d,.\s]*[KkMm]?) abonnés/g, '$1 followers')
    .replace(/Retirer (.+)/, 'Remove $1')
    .replace(/Ouvrir le média (\d+)/, 'Open media $1')
    .replace(/Aperçu éditorial (\d+) (?:pour|de) (.+)/, 'Editorial preview $1 for $2')
    .replace(/Galerie de (.+)/, '$1 gallery');
}
